import{_ as e,o as a,c as t,j as r,a as Z,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"七大魔神力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/7.系列战斗机器人/魔神Z系列/七大魔神力.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/7.系列战斗机器人/魔神Z系列/七大魔神力.md"}'),S={name:"4.资源分区/7.物品与装备/7.载具及随从/战斗机器人/7.系列战斗机器人/魔神Z系列/七大魔神力.md"};function n(s,b,o,d,R,E){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"七大魔神力",tabindex:"-1"},[Z("七大魔神力 "),r("a",{class:"header-anchor",href:"#七大魔神力","aria-label":'Permalink to "七大魔神力"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),p('<h1 id="七大魔神力-1" tabindex="-1">七大魔神力 <a class="header-anchor" href="#七大魔神力-1" aria-label="Permalink to &quot;七大魔神力&quot;">​</a></h1><p>七大魔神力<br> 疯狂科学家兜十藏为了在有限的生命里进行无限的研究，创造梦幻的超级机器人，建造了光子加速器——密涅瓦X接受来自未来的兜十藏的研究资料，在用尽生命研究后将成果又发给过去的自己，在一次次轮回迭代中魔神Z与密涅瓦X被一次次地升级。于是不断进化的魔神Z体内便隐藏了七个科技黑匣子，非常巧合地放在对魔神Z来说相当于印度教瑜伽的查克拉所在的位置，这便是七大魔神力，当七大魔神力完全释放，魔神Z便会进化为魔神ZERO，毁灭一切，成为时间尽头的主宰。<br> 七大魔神力必须依次解放，魔神Z需要按照顺序依次购买魔神力（但不要求完全解放），特殊的，魔神凯撒在某些版本中有着类似魔神力的能力，所以升级为魔神凯撒后可以继承已购买的魔神力，且魔神凯撒不需要按照顺序购买魔神力，因为这是将魔神力作为魔神凯撒所拥有的类似力量购买。但魔神凯撒不能购买第七魔神力，购买第七魔神力的魔神Z也不能升级为魔神凯撒。<br> 完全解放：打开科技黑盒还没有完全解放七大魔神力的力量，需要支付支线与分数进行完全解放。但通过适应与训练也可以做到这点，在你购买某个魔神力经历了一场影片后，你可以改用等价的XP来购买完全解放。</p><p>第一魔神力：再生<br> C+1000<br> 引发与空中元素固定装置类似，但是不同的现象，通过固定空气中的元素，对机体在战斗中所受的破坏进行完全再生。<br> 只要接触任何物质（包括空气之类的气体），机体就获得3快速维修（医疗点36）<br> 进化：在经历一场影片的适应后，再生能力能在破损后瞬间进行恢复，这视为一个S级即死免疫效果<br> 完全解放：<br> B+2000<br> 效果：完全解放再生之力，即使机体被彻底破坏，再生黑盒也能继续运转，不断填补再生机体，在约24小时后机体即可恢复如初，这是一个A级命运来源的复活效果。此外机体获得1点基于护甲值防御类型的全吸收，表现为机体在受到攻击的同时就进行了一定的再生。</p><p>第二魔神力：吸收<br> C+1000<br> 吸收敌人放出的各种能量并转换为自己的力量，也有能量过于巨大，引擎会无法承受的缺陷。在魔神化后能够吸收物质，如吸收大魔神凯撒的凯撒神剑。<br> 机体能够吸收敌人放出的能量，这意味着机体获得2全能量抗力，每轮一次，当机体因此抵消了伤害，则下个回合中机体的攻击获得等同于被第二魔神力提供的能量抗力吸收的伤害的能量加值（也就是说至多为2）<br> 进化：在进行一场影片后，魔神力逐渐适应，2能量抗力改为2全伤害吸收。之后每经历一场影片（也就是说不包括第一场影片）后全伤害吸收增加1点，相应的能获得的能量加值上限也增加1点。<br> 完全解放：<br> B+2000<br> 效果：完全解放吸收魔神力，现在的吸收魔神力能够吸收物质，这导致敌人对机体进行近战攻击时，其自身会被吸收一部分，导致受到损伤，在你受到近战攻击后，若仍保留机体护甲值防御类型的防御，则令攻击者用于此次攻击的一个肢体受到不可豁免的，数值等于你智力附加成功+1的肢体妨碍点数。</p><p>第三魔神力：强化<br> C+1000<br> 使光子力引擎功率的上限以乘法等级上升，所有机体能力大幅度上升，可进一步将其他魔神力量强化。<br> 机体的结构得到加固，机体视为具有购买者驾驶检定主属性的附加成功*1的临时生命与【封闭】，这是光子力充盈加固的结果。当经过一个场景时光子力引擎就会迅速补充光子力，让消耗的临时生命恢复。此外，机体获得【防弹】<br> 完全解放：<br> 完全解放强化魔神力，让其他魔神力得到强化。<br> A+4000<br> 效果：<br> 机体的速度进一步强化，能够自由地使用各种装备，每轮一次，魔神Z第一次造成的伤害翻倍。<br> 第一魔神力得到强化，随着战斗逐渐解锁新的力量，在第一场影片结束后，第一魔神力能够瞬间恢复创伤，这是一种S级创伤来源免疫，第二场影片结束后，第一魔神力能够维持机体在任何环境中保持状态，这是一种S级环境来源免疫，第三场影片结束后，第一魔神力能再生内部的崩坏，这是一种S级毒素来源免疫。<br> 第二魔神力得到强化，机体获得【防能量】【三防】，第二魔神力提供的全伤害吸收增加一，相应的能量加值上限也会加一。</p><p>第四魔神力：高次预测<br> B+2000<br> 达到最大演算的高次预测经由第三种魔神力量进一步强化后能够预测所有的可能性，找出通往未来的，胜利的突破口。<br> 初步解放预测的力量，驾驶员可以使用一个移动动作并支付2意志力启动高次预测能力，在当前场景中机体获得驾驶员驾驶鉴定主属性*1的防御上的洞察加值，因为已经看穿了未来，所以驾驶员的任何攻击忽略对方的闪避防御，这是一个B级别信息来源的忽略闪避防御效果。<br> 完全解放：<br> 完全解放高次预测能力，Z的状况模拟能力达到超绝等级的时候，就跟预测未来是同一回事了<br> S+8000<br> 每轮一次，在受到攻击时可以宣称这是你已经预测到的未来，令这次攻击被完全无效化。这是一个S级信息来源的无敌效果。在你的回合开始时，你可以宣称上一轮发生的是你正预知的未来，让时间回归到你的上一轮开始时，这是一个S级信息来源的未来视效果，所有人的状态也会因此恢复，在非战斗中使用则是将时间倒回12秒前，但由于你只是预测了一次未来，则被回退后的一轮必然是你真实经历的时间，因此你无法让回溯的一轮再次回溯。</p><p>第五魔神力：变态<br> B+2000<br> 无视物理法则的改变身体结构，也能运用在武装方面，例如手臂重构形成强化型火箭飞拳或是切割飞拳，将喷射飞翼的构造变形从而产生南十字星镖，在手臂内侧制造钻头导弹等。在魔神化后能够将武装巨大化以达到增幅威力的效果。<br> 初步解放变态的力量，能够变化出全新的武装用于战斗，现在魔神Z允许购买除 终极凯撒神剑 以外的魔神凯撒专属武装、历史角落的武装、魔神ZERO专属武装。需要注意的是魔神凯撒与魔神ZERO专属武装不兼容，如果购买了魔神ZERO武装的魔神Z升级为魔神凯撒，则魔神ZERO武装变得无法使用。<br> 变态-范围化：机体的任何武装变得可以对攻击范围内的任意数量敌人发动攻击。<br> 变态-强化：机体使用武装进行攻击前可以选择以下三种强化方向之一对武装进行强化，令此次攻击具有相应的特性，切换当前选择的强化方向是一个花招动作。<br> 1&gt;强力：单纯地强化武装的功率，造成更严重的伤害，例如火箭飞拳变成强化火箭飞拳，令此次攻击具有【幻灭】<br> 2&gt;贯穿：变换武装的形态提升单点突破的能力，令此次攻击具有【超级贯穿】<br> 3&gt;适应：自由地变换武装形态，以针对性地对敌人进行攻击，令此次攻击获得{合计值}等同于机体等级*2的高速，在这次攻击中，可以将等额的高速转化为破甲，威猛，破魔。<br> 完全解放<br> A+4000<br> 完全解放变态的力量，进行更大幅度的变化，贯彻魔神Z【魔】的一面<br> 机体的远程武装大幅变化，功率极大加强，可以攻击敏感范围内的任何敌人。<br> 机体的近战武装自由地变得巨大，敏感范围内的目标皆可打击到。<br> 机体本身得到进一步的变化，魔的一面展露无疑，想要接近也是奢望，机体获得基于护甲防御的【反震】，造成精神伤害。</p><p>第六魔神力：因果律兵器<br> A+4000<br> 配合高次预测使用，从无数的未来的可能性中使那胜利的未来转移到所处时空中来。<br> 为了配合因果律并且的使用，高次预测尽可能地预测了所有的未来，这让你洞悉一切。在高次预测启动期间，每回合一次，你可以用一个自由动作用驾驶检定主属性+器用+战斗机器人对抗一个目标的伪装检定，成功后你可以完全得知目标的攻击、防御、豁免、免疫、使用的招式信息、属性等这是一个A级别、信息来源的解析效果。<br> 经过一影片的适应，你将可以自如的改变未来，脱离时空与命运的束缚，你获得S级时空来源免疫与S级命运来源免疫。<br> 完全解放<br> S+8000<br> 将平行时空中胜利的未来覆写到现实中。<br> 在高次预测启动期间，你可以以自由动作从平行时空中找到当前时空中发生的可能性为0%的事件，将其转换到现在的时空中发生，具体来说，在你的回合中，你可以使用一个迅捷动作从以下三种时空中选择一个效果在本轮中生效：<br> 1、传说一瞬：在不同的时空中找到自己做出最好发挥的一次攻击的可能性，将其转化为现实。本回合仅一次，你可以令一次使用载具的攻击检定变为具有【传奇】。<br> 2、必然胜利：在不同的时空中找到自己获得胜利的未来将其转化为现实，本回合你的所有攻击附带S级命运来源的即死效果，意志豁免，因为只有意志才能突破命运。<br> 3、突破神狱：在不同的时空中找到自己突破对方的未来的时空并将其覆盖为现实，本回合你的攻击可以忽略对方的盔甲防御与天生防御，这是一个S级时空来源的效果。<br> 寻找希望：每轮一次，在你的回合中或者你的回合结束时，你可以宣称这是你观测的未来，让时间回到你的回合开始时，重新开始你的回合，寻找更有效的战斗方法，这是一个S级信息来源的未来视效果。</p><p>第七魔神力：魔神化<br> 前提：魔神Z强化到A级<br> 吞噬，同化驾驶者的意志，成为终焉的魔神破坏世界。所幸主神会让你如同SRWV中的甲儿一样得到魔神ZERO的认可，驾驶魔神ZERO在一个时空的分身，拥有究极的魔神的一部分力量。<br> A+4000<br> 购买后魔神Z变成S级载具，终焉的魔神——魔神ZERO，属性与效果替换为以下内容：<br> 体积：112<br> 结构：112<br> 装甲：60<br> 移动速度/轮：160米<br> 魔神化：魔神化后魔神Z变为魔神ZERO，魔神力也便得到加强<br> 魔神意识：一般来说这个情况下魔神ZERO已经拥有了自我意识，但因为得到认可，这台魔神ZERO已经由你驾驶，所以魔神ZERO的意识不对你的载具产生影响（顶多用光子文字和你聊天），因此魔神ZERO如同无意识载具一般不具有属性，但也会获得相应的优劣。<br> 『驾驶舱』驾驶舱为驾驶者和乘客提供全遮蔽效果，并额外为驾驶者和乘客提供5遮蔽防御<br> 『超合金？变态』：魔神ZERO的身躯在强化与吸收魔神力的组合下显然已经不在是原本的超合金Z。魔神ZERO具有【强拦截】，免疫冲击伤害点数造成的减值，由于变态魔神力的强化，魔神ZERO的身体可以自如的变换，如同是由无数微小的原子构成，因此魔神ZERO视为超微型集群。<br> 『预测，吸收』：预测与吸收的力量得到强化，可以针对强大的攻击做出相应的变换进行抵抗，一轮一次，魔神ZERO能免疫一次范围攻击，这是S级变形来源的无敌效果。<br> 『ZERO意志』：ZERO必须是最强的，这是ZERO的意志，在遭遇比自己更强的敌人时会引起ZERO的愤怒，机体具有狂怒12</p><p>St选开（建议别开）：<br> 前提：拥有七大魔神力，且前六大魔神力均完全解放，这是一个套装效果<br> 魔神ZERO的世界<br> SSS+8000<br> 套装效果：<br> 魔神ZERO随手将所有的平行时空合为一体，不再有其他的可能。这是一个SSS级异空间免疫能力，作用范围为全世界。<br> 魔神Z与魔神ZERO是无敌，从诞生开始就是如此，不可能存在比魔神Z更强的存在，这是必然的事实。所有人都会这么想，魔神Z的玩具会成为畅销品，魔神Z的节目会永远在周日播放，魔神Z的一切都是最棒的，魔神Z的一切都是畅销，没有人会有自己能战胜魔神Z或魔神ZERO的念头，若与之为敌，则无法造成伤害，这是一个SS级模因效果，SSS级思维控制效果，SSS级命运来源的无敌效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const l=e(S,[["render",n]]);export{_ as __pageData,l as default};
